"use client";

import { useState, useEffect, Suspense } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { Package2, ArrowRight, Loader2, Key, Lock, Mail } from "lucide-react";

function ResetPasswordForm() {
  const router = useRouter();
  const searchParams = useSearchParams();

  const [email, setEmail] = useState("");
  const [otp, setOtp] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    const qEmail = searchParams.get("email");
    if (qEmail) setEmail(qEmail);
  }, [searchParams]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    if (newPassword.length < 6) {
      setError("Password must be at least 6 characters.");
      setLoading(false);
      return;
    }

    try {
      const res = await fetch("/api/auth/reset-password", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, otp, newPassword }),
      });

      const data = await res.json();

      if (!res.ok) {
        setError(data.error || "Invalid OTP or request failed.");
        setLoading(false);
        return;
      }

      setSuccess(true);
      setTimeout(() => {
        router.push("/login");
      }, 2000);
    } catch {
      setError("An unexpected error occurred.");
      setLoading(false);
    }
  };

  return (
    <>
      <div style={{ textAlign: "center", marginBottom: 32 }}>
        <div
          style={{
            width: 48,
            height: 48,
            borderRadius: "12px",
            background: "var(--accent-gradient)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            margin: "0 auto 16px",
            boxShadow: "var(--accent-glow)",
          }}
        >
          <Package2 size={24} color="white" />
        </div>
        <h1
          style={{
            fontSize: 24,
            fontWeight: 700,
            letterSpacing: "-0.02em",
            marginBottom: 8,
          }}
        >
          Reset Password
        </h1>
        <p style={{ color: "var(--text-muted)", fontSize: 14 }}>
          Enter the OTP sent to your email and a new password
        </p>
      </div>

      {error && (
        <div
          className="animate-fade-in"
          style={{
            background: "var(--danger-bg)",
            border: "1px solid rgba(239, 68, 68, 0.3)",
            borderRadius: "var(--radius-md)",
            padding: "12px 16px",
            fontSize: 13,
            color: "var(--danger)",
            marginBottom: 20,
            textAlign: "center",
          }}
        >
          {error}
        </div>
      )}

      {success ? (
        <div
          className="animate-fade-in"
          style={{
            background: "var(--success-bg)",
            border: "1px solid rgba(16, 185, 129, 0.3)",
            borderRadius: "var(--radius-md)",
            padding: "12px 16px",
            fontSize: 13,
            color: "var(--success)",
            marginBottom: 20,
            textAlign: "center",
          }}
        >
          Password reset successful! Redirecting to login...
        </div>
      ) : (
        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: 16 }}>
            <label className="form-label" htmlFor="email">
              Email Address
            </label>
            <div style={{ position: "relative" }}>
              <Mail
                size={18}
                style={{
                  position: "absolute",
                  left: 12,
                  top: "50%",
                  transform: "translateY(-50%)",
                  color: "var(--text-muted)",
                }}
              />
              <input
                id="email"
                type="email"
                required
                className="input-field"
                placeholder="name@example.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                style={{ paddingLeft: 40 }}
              />
            </div>
          </div>

          <div style={{ marginBottom: 16 }}>
            <label className="form-label" htmlFor="otp">
              6-Digit OTP
            </label>
            <div style={{ position: "relative" }}>
              <Key
                size={18}
                style={{
                  position: "absolute",
                  left: 12,
                  top: "50%",
                  transform: "translateY(-50%)",
                  color: "var(--text-muted)",
                }}
              />
              <input
                id="otp"
                type="text"
                required
                maxLength={6}
                className="input-field"
                placeholder="123456"
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                style={{ paddingLeft: 40, letterSpacing: "2px", fontWeight: "bold" }}
              />
            </div>
          </div>

          <div style={{ marginBottom: 24 }}>
            <label className="form-label" htmlFor="newPassword">
              New Password
            </label>
            <div style={{ position: "relative" }}>
              <Lock
                size={18}
                style={{
                  position: "absolute",
                  left: 12,
                  top: "50%",
                  transform: "translateY(-50%)",
                  color: "var(--text-muted)",
                }}
              />
              <input
                id="newPassword"
                type="password"
                required
                className="input-field"
                placeholder="Enter new password"
                value={newPassword}
                onChange={(e) => setNewPassword(e.target.value)}
                style={{ paddingLeft: 40 }}
              />
            </div>
            <p style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 4 }}>
              Must be at least 6 characters.
            </p>
          </div>

          <button
            type="submit"
            className="btn-primary"
            disabled={loading || !email || !otp || !newPassword}
            style={{
              width: "100%",
              padding: "12px",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: 8,
              fontSize: 14,
              marginBottom: 24,
            }}
          >
            {loading ? (
              <Loader2 size={18} className="animate-spin" />
            ) : (
              <>
                Reset Password <ArrowRight size={18} />
              </>
            )}
          </button>
        </form>
      )}

      <div
        style={{
          textAlign: "center",
          fontSize: 14,
          color: "var(--text-muted)",
        }}
      >
        <Link
          href="/login"
          style={{
            color: "var(--accent-primary)",
            textDecoration: "none",
            fontWeight: 500,
          }}
        >
          Back to sign in
        </Link>
      </div>
    </>
  );
}

export default function ResetPasswordPage() {
  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 20,
        background: "var(--bg-default)",
        position: "relative",
        overflow: "hidden",
      }}
    >
      <div className="bg-glow" style={{ top: "-10%", right: "-5%" }} />
      <div className="bg-glow" style={{ bottom: "-10%", left: "-5%" }} />

      <div
        className="glass-card animate-fade-in"
        style={{
          width: "100%",
          maxWidth: 420,
          padding: "40px 32px",
          position: "relative",
          zIndex: 1,
        }}
      >
        <Suspense fallback={<div style={{ textAlign: "center", padding: "40px", color: "var(--text-muted)" }}>Loading...</div>}>
          <ResetPasswordForm />
        </Suspense>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import {
  ArrowLeft,
  Save,
  Loader2,
  SlidersHorizontal,
} from "lucide-react";

interface Product {
  id: string;
  name: string;
  sku_code: string;
}

interface Location {
  id: string;
  name: string;
  short_code: string;
  warehouse_name: string | null;
  is_scrap: boolean;
}

export default function NewAdjustmentPage() {
  const router = useRouter();
  const [products, setProducts] = useState<Product[]>([]);
  const [locations, setLocations] = useState<Location[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const [productId, setProductId] = useState("");
  const [locationId, setLocationId] = useState("");
  const [physicalCount, setPhysicalCount] = useState(0);
  const [reason, setReason] = useState("");

  useEffect(() => {
    Promise.all([
      fetch("/api/products").then((r) => r.json()),
      fetch("/api/locations").then((r) => r.json()),
    ]).then(([prodData, locData]) => {
      setProducts(
        (prodData.products || []).map((p: { id: string; name: string; sku_code: string }) => ({
          id: p.id,
          name: p.name,
          sku_code: p.sku_code,
        }))
      );
      setLocations(
        (locData.locations || []).filter((l: Location) => !l.is_scrap)
      );
    });
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    if (!productId || !locationId) {
      setError("Product and location are required");
      setLoading(false);
      return;
    }

    try {
      // Find scrap location
      const locRes = await fetch("/api/locations");
      const locData = await locRes.json();
      const scrapLoc = (locData.locations || []).find(
        (l: Location) => l.is_scrap
      );

      if (!scrapLoc) {
        setError("No scrap location found. Please seed the database first.");
        setLoading(false);
        return;
      }

      // Create an adjustment operation
      const res = await fetch("/api/operations", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          type: "Adjustment",
          srcLocationId: locationId,
          destLocationId: scrapLoc.id,
          contact: reason || "Stock Adjustment",
          items: [
            {
              productId,
              demandQty: physicalCount,
            },
          ],
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        setError(data.error || "Failed to create adjustment");
        return;
      }

      router.push(`/operations/${data.operation.id}`);
    } catch {
      setError("Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="animate-fade-in" style={{ maxWidth: 560 }}>
      {/* Header */}
      <div style={{ marginBottom: 24 }}>
        <Link
          href="/adjustments"
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 6,
            color: "var(--text-muted)",
            fontSize: 13,
            textDecoration: "none",
            marginBottom: 12,
          }}
        >
          <ArrowLeft size={14} />
          Back to Adjustments
        </Link>
        <h1
          style={{
            fontSize: 26,
            fontWeight: 700,
            letterSpacing: "-0.02em",
          }}
        >
          New Stock Adjustment
        </h1>
        <p
          style={{
            color: "var(--text-muted)",
            fontSize: 14,
            marginTop: 4,
          }}
        >
          Override recorded stock with a physical count
        </p>
      </div>

      {error && (
        <div
          style={{
            background: "var(--danger-bg)",
            border: "1px solid rgba(239, 68, 68, 0.3)",
            borderRadius: "var(--radius-md)",
            padding: "10px 14px",
            fontSize: 13,
            color: "var(--danger)",
            marginBottom: 20,
          }}
        >
          {error}
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <div className="glass-card" style={{ padding: 24 }}>
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            <div>
              <label className="form-label">Product *</label>
              <select
                className="select-field"
                value={productId}
                onChange={(e) => setProductId(e.target.value)}
                required
              >
                <option value="">Select product</option>
                {products.map((p) => (
                  <option key={p.id} value={p.id}>
                    {p.name} ({p.sku_code})
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="form-label">Location *</label>
              <select
                className="select-field"
                value={locationId}
                onChange={(e) => setLocationId(e.target.value)}
                required
              >
                <option value="">Select location</option>
                {locations.map((l) => (
                  <option key={l.id} value={l.id}>
                    {l.warehouse_name ? `${l.warehouse_name} / ` : ""}
                    {l.name} ({l.short_code})
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="form-label">Physical Count (Qty) *</label>
              <input
                className="input-field"
                type="number"
                min="0"
                step="0.01"
                value={physicalCount}
                onChange={(e) =>
                  setPhysicalCount(parseFloat(e.target.value) || 0)
                }
                required
              />
            </div>

            <div>
              <label className="form-label">Reason / Notes</label>
              <textarea
                className="input-field"
                placeholder="Reason for adjustment..."
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                rows={2}
                style={{ resize: "vertical" }}
              />
            </div>
          </div>
        </div>

        <div
          style={{
            display: "flex",
            gap: 12,
            marginTop: 20,
            justifyContent: "flex-end",
          }}
        >
          <Link
            href="/adjustments"
            className="btn-secondary"
            style={{ textDecoration: "none" }}
          >
            Cancel
          </Link>
          <button
            type="submit"
            className="btn-primary"
            disabled={loading}
            style={{ display: "flex", alignItems: "center", gap: 8 }}
          >
            {loading ? (
              <Loader2 size={16} className="animate-spin" />
            ) : (
              <Save size={16} />
            )}
            {loading ? "Creating..." : "Create Adjustment"}
          </button>
        </div>
      </form>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import {
  ArrowLeft,
  CheckCircle,
  Printer,
  Loader2,
  Package,
  MapPin,
  User,
  Calendar,
  Hash,
} from "lucide-react";
import { formatDateTime, getStatusColor, getTypeColor } from "@/lib/utils";
import ValidationModal from "@/components/ValidationModal";

interface OperationDetail {
  id: string;
  ref_no: string;
  type: string;
  status: string;
  contact: string | null;
  scheduled_date: string | null;
  created_at: string;
  responsible_name: string | null;
  src_location_name: string | null;
  src_location_code: string | null;
  dest_location_name: string | null;
  dest_location_code: string | null;
}

interface OperationItem {
  id: string;
  product_name: string;
  sku_code: string;
  barcode: string | null;
  weight: string;
  demand_qty: string;
  done_qty: string;
}

export default function OperationDetailPage() {
  const params = useParams();
  const router = useRouter();
  const id = params.id as string;

  const [operation, setOperation] = useState<OperationDetail | null>(null);
  const [items, setItems] = useState<OperationItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [validating, setValidating] = useState(false);
  const [error, setError] = useState("");

  const [showValidationModal, setShowValidationModal] = useState(false);

  const fetchData = async () => {
    const res = await fetch(`/api/operations/${id}`);
    const data = await res.json();
    setOperation(data.operation);
    setItems(data.items || []);
    setLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, [id]);

  const handleValidateClick = () => {
    // Check if there are items to validate
    const pendingItems = items.filter(
      (item) => parseFloat(item.done_qty) < parseFloat(item.demand_qty)
    );
    if (pendingItems.length === 0) {
      executeValidation();
    } else {
      setShowValidationModal(true);
    }
  };

  const executeValidation = async () => {
    setShowValidationModal(false);
    setValidating(true);
    setError("");

    try {
      const res = await fetch(`/api/operations/${id}/validate`, {
        method: "POST",
      });
      const data = await res.json();

      if (!res.ok) {
        setError(data.error || "Failed to validate");
        return;
      }

      fetchData();
    } catch {
      setError("Something went wrong");
    } finally {
      setValidating(false);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  if (loading) {
    return (
      <div style={{ padding: 40, color: "var(--text-muted)" }}>
        Loading operation...
      </div>
    );
  }

  if (!operation) {
    return (
      <div style={{ padding: 40, color: "var(--text-muted)" }}>
        Operation not found
      </div>
    );
  }

  return (
    <div className="animate-fade-in" style={{ maxWidth: 800 }}>
      {/* Header */}
      <div style={{ marginBottom: 24 }}>
        <Link
          href="/operations"
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 6,
            color: "var(--text-muted)",
            fontSize: 13,
            textDecoration: "none",
            marginBottom: 12,
          }}
        >
          <ArrowLeft size={14} />
          Back to Operations
        </Link>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            flexWrap: "wrap",
            gap: 12,
          }}
        >
          <div>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: 12,
                marginBottom: 4,
              }}
            >
              <h1
                style={{
                  fontSize: 26,
                  fontWeight: 700,
                  letterSpacing: "-0.02em",
                  fontFamily: "var(--font-mono)",
                }}
              >
                {operation.ref_no}
              </h1>
              <span
                className={`status-badge ${getTypeColor(operation.type)}`}
              >
                {operation.type}
              </span>
              <span
                className={`status-badge ${getStatusColor(operation.status)}`}
              >
                {operation.status}
              </span>
            </div>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button
              onClick={handlePrint}
              className="btn-secondary"
              style={{ display: "flex", alignItems: "center", gap: 6 }}
            >
              <Printer size={14} />
              Print
            </button>
            {operation.status !== "Done" && (
              <button
                onClick={handleValidateClick}
                className="btn-primary"
                disabled={validating}
                style={{ display: "flex", alignItems: "center", gap: 6 }}
              >
                {validating ? (
                  <Loader2 size={14} className="animate-spin" />
                ) : (
                  <CheckCircle size={14} />
                )}
                {validating ? "Validating..." : "Validate"}
              </button>
            )}
          </div>
        </div>
      </div>

      {error && (
        <div
          style={{
            background: "var(--danger-bg)",
            border: "1px solid rgba(239, 68, 68, 0.3)",
            borderRadius: "var(--radius-md)",
            padding: "10px 14px",
            fontSize: 13,
            color: "var(--danger)",
            marginBottom: 20,
          }}
        >
          {error}
        </div>
      )}

      {/* Info Cards */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
          gap: 12,
          marginBottom: 20,
        }}
      >
        {[
          {
            icon: User,
            label: "Contact",
            value: operation.contact || "ΓÇö",
            color: "#6366f1",
          },
          {
            icon: MapPin,
            label: "From ΓåÆ To",
            value: `${operation.src_location_name || "ΓÇö"} ΓåÆ ${operation.dest_location_name || "ΓÇö"}`,
            color: "#10b981",
          },
          {
            icon: Calendar,
            label: "Scheduled",
            value: formatDateTime(operation.scheduled_date),
            color: "#f59e0b",
          },
          {
            icon: Hash,
            label: "Created",
            value: formatDateTime(operation.created_at),
            color: "#8b5cf6",
          },
        ].map((card) => (
          <div
            key={card.label}
            className="glass-card"
            style={{ padding: 16 }}
          >
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: 8,
                marginBottom: 8,
              }}
            >
              <card.icon size={14} color={card.color} />
              <span
                style={{
                  fontSize: 12,
                  color: "var(--text-muted)",
                  fontWeight: 500,
                }}
              >
                {card.label}
              </span>
            </div>
            <p style={{ fontSize: 14, fontWeight: 500 }}>{card.value}</p>
          </div>
        ))}
      </div>

      {/* Line Items */}
      <div className="glass-card" style={{ overflow: "hidden" }}>
        <div
          style={{
            padding: "16px 20px",
            borderBottom: "1px solid var(--border-primary)",
          }}
        >
          <h3 style={{ fontSize: 15, fontWeight: 600 }}>Line Items</h3>
        </div>
        {items.length === 0 ? (
          <div className="empty-state">
            <Package size={36} />
            <p>No items in this operation</p>
          </div>
        ) : (
          <table className="data-table">
            <thead>
              <tr>
                <th>Product</th>
                <th>SKU</th>
                <th>Demand Qty</th>
                <th>Done Qty</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item) => (
                <tr key={item.id} style={{ cursor: "default" }}>
                  <td style={{ fontWeight: 500 }}>{item.product_name}</td>
                  <td
                    style={{
                      fontFamily: "var(--font-mono)",
                      fontSize: 13,
                      color: "var(--text-secondary)",
                    }}
                  >
                    {item.sku_code}
                  </td>
                  <td>{parseFloat(item.demand_qty).toFixed(0)}</td>
                  <td
                    style={{
                      fontWeight: 600,
                      color:
                        parseFloat(item.done_qty) >=
                        parseFloat(item.demand_qty)
                          ? "var(--success)"
                          : "var(--text-primary)",
                    }}
                  >
                    {parseFloat(item.done_qty).toFixed(0)}
                    {parseFloat(item.done_qty) >=
                      parseFloat(item.demand_qty) && (
                      <CheckCircle
                        size={14}
                        style={{ marginLeft: 6, verticalAlign: "middle" }}
                        color="var(--success)"
                      />
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <ValidationModal
        items={items}
        isOpen={showValidationModal}
        onClose={() => setShowValidationModal(false)}
        onConfirm={executeValidation}
      />
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { ArrowLeft, Save, Loader2, Plus, Trash2 } from "lucide-react";

interface Location {
  id: string;
  name: string;
  short_code: string;
  warehouse_name: string | null;
  is_scrap: boolean;
}

interface Product {
  id: string;
  name: string;
  sku_code: string;
}

interface LineItem {
  productId: string;
  demandQty: number;
}

export default function NewOperationPage() {
  const router = useRouter();
  const [locations, setLocations] = useState<Location[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const [type, setType] = useState("Receipt");
  const [srcLocationId, setSrcLocationId] = useState("");
  const [destLocationId, setDestLocationId] = useState("");
  const [contact, setContact] = useState("");
  const [scheduledDate, setScheduledDate] = useState("");
  const [items, setItems] = useState<LineItem[]>([
    { productId: "", demandQty: 1 },
  ]);

  useEffect(() => {
    Promise.all([
      fetch("/api/locations").then((r) => r.json()),
      fetch("/api/products").then((r) => r.json()),
    ]).then(([locData, prodData]) => {
      setLocations(locData.locations || []);
      setProducts(
        (prodData.products || []).map((p: { id: string; name: string; sku_code: string }) => ({
          id: p.id,
          name: p.name,
          sku_code: p.sku_code,
        }))
      );

      // Auto-set locations based on type
      const locs = locData.locations || [];
      const inputLoc = locs.find((l: Location) => l.short_code === "WH/INPUT");
      const outputLoc = locs.find((l: Location) => l.short_code === "WH/OUTPUT");
      const stockLoc = locs.find((l: Location) => l.short_code === "WH/STOCK");

      if (inputLoc && stockLoc) {
        setSrcLocationId(inputLoc.id);
        setDestLocationId(stockLoc.id);
      }
    });
  }, []);

  // Auto-set locations when type changes
  useEffect(() => {
    const inputLoc = locations.find((l) => l.short_code === "WH/INPUT");
    const outputLoc = locations.find((l) => l.short_code === "WH/OUTPUT");
    const stockLoc = locations.find((l) => l.short_code === "WH/STOCK");
    const scrapLoc = locations.find((l) => l.short_code === "WH/SCRAP");

    switch (type) {
      case "Receipt":
        if (inputLoc) setSrcLocationId(inputLoc.id);
        if (stockLoc) setDestLocationId(stockLoc.id);
        break;
      case "Delivery":
        if (stockLoc) setSrcLocationId(stockLoc.id);
        if (outputLoc) setDestLocationId(outputLoc.id);
        break;
      case "Adjustment":
        if (stockLoc) setSrcLocationId(stockLoc.id);
        if (scrapLoc) setDestLocationId(scrapLoc.id);
        break;
      default:
        break;
    }
  }, [type, locations]);

  const addItem = () => {
    setItems([...items, { productId: "", demandQty: 1 }]);
  };

  const removeItem = (index: number) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const updateItem = (index: number, field: string, value: string | number) => {
    const updated = [...items];
    updated[index] = { ...updated[index], [field]: value };
    setItems(updated);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    const validItems = items.filter((i) => i.productId && i.demandQty > 0);
    if (validItems.length === 0) {
      setError("At least one valid line item is required");
      setLoading(false);
      return;
    }

    try {
      const res = await fetch("/api/operations", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          type,
          srcLocationId,
          destLocationId,
          contact: contact || null,
          scheduledDate: scheduledDate || null,
          items: validItems,
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        setError(data.error || "Failed to create operation");
        return;
      }

      router.push("/operations");
    } catch {
      setError("Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="animate-fade-in" style={{ maxWidth: 720 }}>
      {/* Header */}
      <div style={{ marginBottom: 24 }}>
        <Link
          href="/operations"
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 6,
            color: "var(--text-muted)",
            fontSize: 13,
            textDecoration: "none",
            marginBottom: 12,
          }}
        >
          <ArrowLeft size={14} />
          Back to Operations
        </Link>
        <h1
          style={{
            fontSize: 26,
            fontWeight: 700,
            letterSpacing: "-0.02em",
          }}
        >
          New Operation
        </h1>
      </div>

      {error && (
        <div
          style={{
            background: "var(--danger-bg)",
            border: "1px solid rgba(239, 68, 68, 0.3)",
            borderRadius: "var(--radius-md)",
            padding: "10px 14px",
            fontSize: 13,
            color: "var(--danger)",
            marginBottom: 20,
          }}
        >
          {error}
        </div>
      )}

      <form onSubmit={handleSubmit}>
        {/* Operation Info */}
        <div className="glass-card" style={{ padding: 24, marginBottom: 16 }}>
          <h3
            style={{
              fontSize: 15,
              fontWeight: 600,
              marginBottom: 16,
              color: "var(--text-secondary)",
            }}
          >
            Operation Details
          </h3>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: 16,
            }}
          >
            <div>
              <label className="form-label">Operation Type *</label>
              <select
                className="select-field"
                value={type}
                onChange={(e) => setType(e.target.value)}
              >
                <option value="Receipt">Receipt (Incoming)</option>
                <option value="Delivery">Delivery (Outgoing)</option>
                <option value="Internal">Internal Transfer</option>
                <option value="Adjustment">Adjustment</option>
              </select>
            </div>
            <div>
              <label className="form-label">
                {type === "Receipt"
                  ? "Vendor"
                  : type === "Delivery"
                    ? "Customer"
                    : "Contact"}
              </label>
              <input
                className="input-field"
                placeholder={
                  type === "Receipt"
                    ? "Vendor name"
                    : type === "Delivery"
                      ? "Customer name"
                      : "Contact name"
                }
                value={contact}
                onChange={(e) => setContact(e.target.value)}
              />
            </div>
            <div>
              <label className="form-label">Source Location *</label>
              <select
                className="select-field"
                value={srcLocationId}
                onChange={(e) => setSrcLocationId(e.target.value)}
                required
              >
                <option value="">Select location</option>
                {locations.map((l) => (
                  <option key={l.id} value={l.id}>
                    {l.warehouse_name ? `${l.warehouse_name} / ` : ""}
                    {l.name} ({l.short_code})
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="form-label">Destination Location *</label>
              <select
                className="select-field"
                value={destLocationId}
                onChange={(e) => setDestLocationId(e.target.value)}
                required
              >
                <option value="">Select location</option>
                {locations.map((l) => (
                  <option key={l.id} value={l.id}>
                    {l.warehouse_name ? `${l.warehouse_name} / ` : ""}
                    {l.name} ({l.short_code})
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="form-label">Scheduled Date</label>
              <input
                className="input-field"
                type="datetime-local"
                value={scheduledDate}
                onChange={(e) => setScheduledDate(e.target.value)}
              />
            </div>
          </div>
        </div>

        {/* Line Items */}
        <div className="glass-card" style={{ padding: 24, marginBottom: 16 }}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              marginBottom: 16,
            }}
          >
            <h3
              style={{
                fontSize: 15,
                fontWeight: 600,
                color: "var(--text-secondary)",
              }}
            >
              Line Items
            </h3>
            <button
              type="button"
              onClick={addItem}
              className="btn-secondary"
              style={{
                display: "flex",
                alignItems: "center",
                gap: 6,
                padding: "6px 12px",
                fontSize: 13,
              }}
            >
              <Plus size={14} />
              Add Item
            </button>
          </div>

          {items.map((item, index) => (
            <div
              key={index}
              style={{
                display: "flex",
                gap: 12,
                marginBottom: 12,
                alignItems: "flex-end",
              }}
            >
              <div style={{ flex: 2 }}>
                {index === 0 && (
                  <label className="form-label">Product</label>
                )}
                <select
                  className="select-field"
                  value={item.productId}
                  onChange={(e) =>
                    updateItem(index, "productId", e.target.value)
                  }
                  required
                >
                  <option value="">Select product</option>
                  {products.map((p) => (
                    <option key={p.id} value={p.id}>
                      {p.name} ({p.sku_code})
                    </option>
                  ))}
                </select>
              </div>
              <div style={{ flex: 1 }}>
                {index === 0 && (
                  <label className="form-label">Demand Qty</label>
                )}
                <input
                  className="input-field"
                  type="number"
                  min="1"
                  value={item.demandQty}
                  onChange={(e) =>
                    updateItem(
                      index,
                      "demandQty",
                      parseFloat(e.target.value) || 0
                    )
                  }
                  required
                />
              </div>
              {items.length > 1 && (
                <button
                  type="button"
                  onClick={() => removeItem(index)}
                  style={{
                    padding: 10,
                    background: "var(--danger-bg)",
                    border: "1px solid rgba(239, 68, 68, 0.3)",
                    borderRadius: "var(--radius-md)",
                    cursor: "pointer",
                    color: "var(--danger)",
                    marginBottom: index === 0 ? 0 : 0,
                  }}
                >
                  <Trash2 size={14} />
                </button>
              )}
            </div>
          ))}
        </div>

        {/* Actions */}
        <div
          style={{
            display: "flex",
            gap: 12,
            justifyContent: "flex-end",
          }}
        >
          <Link
            href="/operations"
            className="btn-secondary"
            style={{ textDecoration: "none" }}
          >
            Cancel
          </Link>
          <button
            type="submit"
            className="btn-primary"
            disabled={loading}
            style={{ display: "flex", alignItems: "center", gap: 8 }}
          >
            {loading ? (
              <Loader2 size={16} className="animate-spin" />
            ) : (
              <Save size={16} />
            )}
            {loading ? "Creating..." : "Create Operation"}
          </button>
        </div>
      </form>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useSearchParams } from "next/navigation";
import {
  Search,
  Plus,
  ClipboardList,
  Filter,
  ChevronRight,
} from "lucide-react";
import { formatDate, getStatusColor, getTypeColor } from "@/lib/utils";

interface Operation {
  id: string;
  ref_no: string;
  type: string;
  status: string;
  contact: string | null;
  scheduled_date: string | null;
  created_at: string;
  responsible_name: string | null;
  src_location_name: string | null;
  dest_location_name: string | null;
}

export default function OperationsPage() {
  const searchParams = useSearchParams();
  const typeParam = searchParams.get("type") || "";

  const [operations, setOperations] = useState<Operation[]>([]);
  const [search, setSearch] = useState("");
  const [typeFilter, setTypeFilter] = useState(typeParam);
  const [statusFilter, setStatusFilter] = useState("");
  const [loading, setLoading] = useState(true);

  const fetchOperations = async () => {
    setLoading(true);
    const params = new URLSearchParams();
    if (search) params.set("search", search);
    if (typeFilter) params.set("type", typeFilter);
    if (statusFilter) params.set("status", statusFilter);
    const res = await fetch(`/api/operations?${params}`);
    const data = await res.json();
    setOperations(data.operations || []);
    setLoading(false);
  };

  useEffect(() => {
    setTypeFilter(typeParam);
  }, [typeParam]);

  useEffect(() => {
    const timer = setTimeout(fetchOperations, 300);
    return () => clearTimeout(timer);
  }, [search, typeFilter, statusFilter]);

  const pageTitle = typeFilter
    ? `${typeFilter}s`
    : "All Operations";

  return (
    <div className="animate-fade-in">
      {/* Header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 24,
          flexWrap: "wrap",
          gap: 12,
        }}
      >
        <div>
          <h1
            style={{
              fontSize: 26,
              fontWeight: 700,
              letterSpacing: "-0.02em",
              marginBottom: 4,
            }}
          >
            {pageTitle}
          </h1>
          <p style={{ color: "var(--text-muted)", fontSize: 14 }}>
            Manage inventory operations
          </p>
        </div>
        <Link
          href="/operations/new"
          className="btn-primary"
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 8,
            textDecoration: "none",
          }}
        >
          <Plus size={16} />
          New Operation
        </Link>
      </div>

      {/* Filters */}
      <div
        className="glass-card"
        style={{
          padding: 16,
          marginBottom: 20,
          display: "flex",
          gap: 12,
          flexWrap: "wrap",
        }}
      >
        <div style={{ flex: 1, minWidth: 200, position: "relative" }}>
          <Search
            size={16}
            style={{
              position: "absolute",
              left: 12,
              top: "50%",
              transform: "translateY(-50%)",
              color: "var(--text-muted)",
            }}
          />
          <input
            className="input-field"
            placeholder="Search by reference or contact..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{ paddingLeft: 36 }}
          />
        </div>
        <div style={{ minWidth: 150 }}>
          <select
